const { Client, Intents, Permissions } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { Routes } = require('discord-api-types/v10');

// Replace with your bot token
const token = 'YOUR_BOT_TOKEN';

// Replace with your application ID
const applicationId = 'YOUR_APPLICATION_ID';

// Intents required for the bot to function
const intents = new IntentsBitField([
    Intents.FLAGS.GUILDS,
    Intents.FLAGS.GUILD_MESSAGES,
    Intents.FLAGS.GUILD_MEMBERS
]);

// Create the client
const client = new Client({ intents });

// Define the ban command
const banCommand = {
    name: 'ban',
    description: 'Ban a user from the server.',
    options: [
        {
            name: 'member',
            description: 'The member to ban',
            type: 'USER',
            required: true
        },
        {
            name: 'reason',
            description: 'The reason for the ban',
            type: 'STRING',
            required: false
        }
    ],
    defaultPermission: false
};

// Register the command
const rest = new REST({ version: '10' }).setToken(token);

(async () => {
    try {
        console.log('Registering commands...');
        await rest.put(Routes.applicationCommands(applicationId), { body: [banCommand] });
        console.log('Commands registered successfully!');
    } catch (error) {
        console.error('Error registering commands:', error);
    }
})();

// Event listener for when the client is ready
client.once('ready', () => {
    console.log(`Logged in as ${client.user.tag}`);
});

// Event listener for slash commands
client.on('interactionCreate', async (interaction) => {
    if (!interaction.isCommand()) return;

    if (interaction.commandName === 'ban') {
        const member = interaction.options.getMember('member');
        const reason = interaction.options.getString('reason') || 'No reason provided';

        // Check if the user has permission to ban
        if (!interaction.memberPermissions.has(Permissions.FLAGS.BAN_MEMBERS)) {
            return interaction.reply({ content: 'You don\'t have permission to ban users.', ephemeral: true });
        }

        // Check if the member is the same as the user
        if (member.id === interaction.user.id) {
            return interaction.reply({ content: 'You cannot ban yourself.', ephemeral: true });
        }

        // Check if the member is a bot
        if (member.user.bot) {
            return interaction.reply({ content: 'You cannot ban a bot.', ephemeral: true });
        }

        // Check if the member is already banned
        try {
            const ban = await member.bans.fetch();
            if (ban.has(member.id)) {
                return interaction.reply({ content: 'This user is already banned.', ephemeral: true });
            }
        } catch (e) {
            console.error(e);
        }

        // Ban the user
        try {
            await member.ban({ reason });
            interaction.reply({ content: `${member} has been banned. Reason: ${reason}`, ephemeral: true });
        } catch (e) {
            console.error(e);
            interaction.reply({ content: 'I couldn\'t ban this user.', ephemeral: true });
        }
    }
});

// Login the bot
client.login(token);
```

