Here's a simple C++ function that converts **basic Markdown** into **HTML**. This implementation supports:

- **Bold (`**text**` → `<strong>text</strong>`**
- **Italic (`*text*` → `<em>text</em>`**
- **Headers (`# Header` → `<h1>Header</h1>`**
- **Unordered lists (`- item` → `<ul><li>item</li></ul>`)

Note: This is a **basic** Markdown parser and does **not** handle all Markdown syntax. For full Markdown to HTML conversion, consider using a library like [markdown.h](https://github.com/aaets/Markdown) or [pandoc](https://pandoc.org/).

---

### ✅ C++ Function: Markdown to HTML

```cpp
#include <string>
#include <vector>
#include <sstream>
#include <algorithm>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::istringstream iss(markdown);
    std::string line;
    bool inList = false;

    while (std::getline(iss, line)) {
        // Remove leading/trailing whitespace
        line.erase(0, line.find_first_not_of(" \t"));
        line.erase(line.find_last_not_of(" \t") + 1);

        // Check for headers
        if (line.substr(0, 1) == "#") {
            size_t count = 0;
            while (count < line.length() && line[count] == '#') {
                ++count;
            }
            if (count >= 1 && count <= 6) {
                html += "<h" + std::to_string(count) + ">" + line.substr(count) + "</h" + std::to_string(count) + ">\n";
                continue;
            }
        }

        // Check for unordered list
        if (line.substr(0, 1) == "-") {
            if (!inList) {
                html += "<ul>\n";
                inList = true;
            }
            html += "<li>" + line.substr(1) + "</li>\n";
            continue;
        }

        // Check for bold
        size_t boldStart = line.find("**");
        while (boldStart != std::string::npos) {
            size_t boldEnd = line.find("**", boldStart + 2);
            if (boldEnd != std::string::npos) {
                html += line.substr(0, boldStart);
                html += "<strong>" + line.substr(boldStart + 2, boldEnd - boldStart - 2) + "</strong>";
                line = line.substr(boldEnd + 2);
                boldStart = line.find("**");
            } else {
                break;
            }
        }

        // Check for italic
        size_t italicStart = line.find("*");
        while (italicStart != std::string::npos) {
            size_t italicEnd = line.find("*", italicStart + 1);
            if (italicEnd != std::string::npos) {
                html += line.substr(0, italicStart);
                html += "<em>" + line.substr(italicStart + 1, italicEnd - italicStart - 1) + "</em>";
                line = line.substr(italicEnd + 1);
                italicStart = line.find("*");
            } else {
                break;
            }
        }

        // Append remaining text
        html += line + "\n";
    }

    // Close any open list
    if (inList) {
        html += "</ul>\n";
    }

    return html;
}
```

---

### ✅ Example Usage

```cpp
#include <iostream>

int main() {
    std::string markdown = R"(
# Header
**Bold text**
*Italic text*
- Item 1
- Item 2
)";

    std::string html = markdownToHtml(markdown);
    std::cout << html;
    return 0;
}
```

---

### ✅ Output

```html
<h1>Header</h1>
<strong>Bold text</strong>
<em>Italic text</em>
<ul>
<li>Item 1</li>
<li>Item 2</li>
</ul>
```

