### 3. `main.c` – Snake Game Code

```c
#include <SDL2/SDL.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define SCREEN_WIDTH 800
#define SCREEN_HEIGHT 600
#define SNAKE_BLOCK_SIZE 20
#define SNAKE_SPEED 100 // milliseconds

typedef struct {
    int x, y;
    SDL_Texture *texture;
} SnakeSegment;

typedef struct {
    int x, y;
    SDL_Texture *texture;
} Food;

typedef struct {
    int direction;
    int score;
    int game_over;
} GameState;

void initGame(GameState *state, SDL_Renderer *renderer);
void handleInput(SDL_Event *event, GameState *state);
void updateGame(GameState *state, SDL_Renderer *renderer);
void renderGame(SDL_Renderer *renderer, GameState *state);
void loadImages(SDL_Renderer *renderer, SnakeSegment *snake, Food *food);
void freeResources(SDL_Texture *head, SDL_Texture *body, SDL_Texture *food);

int main(int argc, char *argv[]) {
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window *window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, 0);
    SDL_Renderer *renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    GameState state;
    initGame(&state, renderer);

    SDL_Event event;
    int running = 1;

    while (running) {
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                running = 0;
            }
            handleInput(&event, &state);
        }

        updateGame(&state, renderer);
        renderGame(renderer, &state);

        SDL_RenderPresent(renderer);
        SDL_Delay(SNAKE_SPEED);
    }

    freeResources(state.snake->texture, state.snake->next->texture, state.food.texture);
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}

void initGame(GameState *state, SDL_Renderer *renderer) {
    state->score = 0;
    state->game_over = 0;
    state->direction = 0; // 0 = right, 1 = down, 2 = left, 3 = up
    state->snake = (SnakeSegment *)malloc(sizeof(SnakeSegment));
    state->snake->x = SCREEN_WIDTH / 2;
    state->snake->y = SCREEN_HEIGHT / 2;
    state->snake->texture = NULL;

    state->food = (Food){0, 0, NULL};

    loadImages(renderer, state->snake, &state->food);
}

void handleInput(SDL_Event *event, GameState *state) {
    if (event->type == SDL_KEYDOWN) {
        switch (event->key.keysym.sym) {
            case SDLK_LEFT:
                if (state->direction != 2) state->direction = 0;
                break;
            case SDLK_RIGHT:
                if (state->direction != 0) state->direction = 2;
                break;
            case SDLK_UP:
                if (state->direction != 3) state->direction = 1;
                break;
            case SDLK_DOWN:
                if (state->direction != 1) state->direction = 3;
                break;
            case SDLK_ESCAPE:
                exit(0);
        }
    }
}

void updateGame(GameState *state, SDL_Renderer *renderer) {
    if (state->game_over) return;

    // Move snake
    SnakeSegment *new_head = (SnakeSegment *)malloc(sizeof(SnakeSegment));
    switch (state->direction) {
        case 0: new_head->x = state->snake->x - SNAKE_BLOCK_SIZE; new_head->y = state->snake->y; break;
        case 1: new_head->x = state->snake->x; new_head->y = state->snake->y - SNAKE_BLOCK_SIZE; break;
        case 2: new_head->x = state->snake->x + SNAKE_BLOCK_SIZE; new_head->y = state->snake->y; break;
        case 3: new_head->x = state->snake->x; new_head->y = state->snake->y + SNAKE_BLOCK_SIZE; break;
    }

    // Check collision with walls
    if (new_head->x < 0 || new_head->x >= SCREEN_WIDTH || new_head->y < 0 || new_head->y >= SCREEN_HEIGHT) {
        state->game_over = 1;
        return;
    }

    // Check collision with self
    SnakeSegment *current = state->snake;
    while (current->next) {
        if (current->x == new_head->x && current->y == new_head->y) {
            state->game_over = 1;
            return;
        }
        current = current->next;
    }

    // Check if food is eaten
    if (new_head->x == state->food.x && new_head->y == state->food.y) {
        state->score++;
        // Generate new food
        state->food.x = rand() % (SCREEN_WIDTH / SNAKE_BLOCK_SIZE) * SNAKE_BLOCK_SIZE;
        state->food.y = rand() % (SCREEN_HEIGHT / SNAKE_BLOCK_SIZE) * SNAKE_BLOCK_SIZE;
    } else {
        // Remove tail
        SnakeSegment *tail = state->snake;
        while (tail->next->next) {
            tail = tail->next;
        }
        free(tail->next);
        tail->next = NULL;
    }

    new_head->next = state->snake;
    state->snake = new_head;
}

void renderGame(SDL_Renderer *renderer, GameState *state) {
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Draw snake
    SnakeSegment *current = state->snake;
    while (current) {
        SDL_Rect rect = {current->x, current->y, SNAKE_BLOCK_SIZE, SNAKE_BLOCK_SIZE};
        SDL_RenderCopy(renderer, current->texture, NULL, &rect);
        current = current->next;
    }

    // Draw food
    SDL_Rect food_rect = {state->food.x, state->food.y, SNAKE_BLOCK_SIZE, SNAKE_BLOCK_SIZE};
    SDL_RenderCopy(renderer, state->food.texture, NULL, &food_rect);

    SDL_RenderPresent(renderer);
}

void loadImages(SDL_Renderer *renderer, SnakeSegment *snake, Food *food) {
    // Load snake head
    snake->texture = SDL_CreateTextureFromSurface(renderer, SDL_LoadBMP("images/snake_head.png"));
    // Load snake body
    snake->next = (SnakeSegment *)malloc(sizeof(SnakeSegment));
    snake->next->texture = SDL_CreateTextureFromSurface(renderer, SDL_LoadBMP("images/snake_body.png"));
    // Load food
    food->texture = SDL_CreateTextureFromSurface(renderer, SDL_LoadBMP("images/food.png"));
}

void freeResources(SDL_Texture *head, SDL_Texture *body, SDL_Texture *food) {
    SDL_DestroyTexture(head);
    SDL_DestroyTexture(body);
    SDL_DestroyTexture(food);
}
```

