Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word:

### ✅ Features:
- Reads a text file line by line.
- Counts how many times a specific word appears in the file.
- Case-insensitive matching (you can modify this if needed).

---

### 📄 `word_count.cpp`

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>
#include <cctype>

using namespace std;

int main() {
    string filename;
    string targetWord;
    string line;
    int count = 0;

    // Get the filename and target word from user
    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to count: ";
    cin >> targetWord;

    // Convert target word to lowercase for case-insensitive comparison
    transform(targetWord.begin(), targetWord.end(), targetWord.begin(), ::tolower);

    // Open the file
    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error: Could not open file " << filename << endl;
        return 1;
    }

    // Read the file line by line
    while (getline(file, line)) {
        // Convert the line to lowercase for case-insensitive comparison
        transform(line.begin(), line.end(), line.begin(), ::tolower);

        // Count occurrences of the target word in the line
        size_t pos = 0;
        while ((pos = line.find(targetWord, pos)) != string::npos) {
            count++;
            pos += targetWord.length(); // Move past this occurrence
        }
    }

    // Close the file
    file.close();

    // Output the result
    cout << "The word \"" << targetWord << "\" appears " << count << " times in the file." << endl;

    return 0;
}
```

---

### 💡 How to Compile and Run

